    const char *dir = "/tmp/kf_inotify";
    unlink("/tmp/kf_inotify/test.txt");
    rmdir(dir);
    mkdir(dir, 0755);

    int fd = inotify_init();
    if (fd == -1) { perror("inotify_init"); return 1; }

    int wd = inotify_add_watch(fd, dir, IN_CREATE);
    if (wd == -1) { perror("inotify_add_watch"); close(fd); return 1; }

    FILE *f = fopen("/tmp/kf_inotify/test.txt", "w");
    fprintf(f, "hello");
    fclose(f);

    struct pollfd pfd = {fd, POLLIN, 0};
    int ret = poll(&pfd, 1, 1000);
    if (ret > 0) {
        char buf[BUF_LEN];
        ssize_t len = read(fd, buf, sizeof(buf));
        if (len > 0) {
            struct inotify_event *event = (struct inotify_event *)buf;
            printf("Evenement detecte\n");
            printf("Fichier : %s\n", event->name);
            printf("Creation : %d\n", (event->mask & IN_CREATE) ? 1 : 0);
        }
    }

    inotify_rm_watch(fd, wd);
