/* == EXEMPLE ================================================
 * Surveiller les modifications d'un fichier avec inotify
 * inotify_init() cree l'instance, inotify_add_watch() ajoute
 * un chemin, read() lit les evenements.
 * =========================================================== */
void example_watch_modify(void) {
    const char *path = "/tmp/kf_ex_watch";
    FILE *f = fopen(path, "w"); fprintf(f, "init"); fclose(f);
    int fd = inotify_init();
    int wd = inotify_add_watch(fd, path, IN_MODIFY);
    /* modifier le fichier */
    f = fopen(path, "a"); fprintf(f, " added"); fclose(f);
    struct pollfd pfd = {fd, POLLIN, 0};
    if (poll(&pfd, 1, 1000) > 0) {
        char buf[BUF_LEN];
        read(fd, buf, sizeof(buf));
        printf("Modification detectee !\n");
    }
    inotify_rm_watch(fd, wd);
    close(fd); unlink(path);
}

